  async analyzeCustomSample(description: string, bio?: Biometrics): Promise<AnalysisResult> {
      // 1. Check for basic API key validity
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
          console.warn('Invalid API Key, returning inference result.');
          return this.getInferenceResult(description, bio);
      }

      let bioString = '';
      if (bio) {
        if (bio.hemoglobin) bioString += `- Hemoglobin: ${bio.hemoglobin} g/dL (Normal: 12-16)\n`;
        if (bio.wbc) bioString += `- WBC Count: ${bio.wbc} K/mcL (Normal: 4.5-11)\n`;
        if (bio.mcv) bioString += `- MCV: ${bio.mcv} fL (Normal: 80-100)\n`;
        if (bio.platelets) bioString += `- Platelets: ${bio.platelets} K/mcL (Normal: 150-450)\n`;
      }

      const prompt = `
        Act as a hematology analyzer. Generate a simulated JSON blood report for this clinical input: "${description}".

        ${bioString ? 'CLINICAL METRICS PROVIDED (Use these to strictly determine diagnosis):' : ''}
        ${bioString}

        INSTRUCTIONS:
        1. Analyze the symptoms and clinical context deeply. 
           - "Tired, pale" -> likely Iron Deficiency Anemia.
           - "Joint pain, family history" -> likely Sickle Cell.
           - "Fever, travel, chills" -> likely Malaria.
           - "Bruising, bleeding, weight loss" -> likely Acute Leukemia (AML).
           - "Elderly, painless swollen nodes, repeated infections" -> likely Chronic Lymphocytic Leukemia (CLL).
           - "Headache, itching after shower, red face" -> likely Polycythemia Vera.
           - "Teenager, sore throat, extreme fatigue, swollen glands" -> likely Infectious Mononucleosis.
        2. Incorporate the provided metrics:
           - High WBC (>15) -> Likely Infection or Acute Leukemia.
           - Very High WBC (>50) with high lymphocytes -> Chronic Lymphocytic Leukemia (CLL).
           - High WBC (12-25) with atypical lymphocytes -> Infectious Mononucleosis.
           - Low Hemoglobin (<12) -> Anemia.
           - Very High Hemoglobin (>18) or Hematocrit (>55) -> Polycythemia Vera.
           - Low MCV (<80) -> Microcytic (Iron Deficiency or Thalassemia).
           - Low Platelets (<150) -> Thrombocytopenia (Leukemia/Malaria).
        3. If metrics are normal and description is healthy, output "Healthy Control".
        4. Do NOT default to "Healthy" if there are clear abnormal metrics or symptoms.

        Include a random mock gene sequence string (ACGT...) around 80 chars long.
        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt);
  }

  async analyzeImage(imageBase64: string): Promise<AnalysisResult> {
       const apiKey = process.env['API_KEY'];
       if (!apiKey || apiKey.length < 10) {
          return this.getInferenceResult('image analysis fallback');
       }

      const prompt = `
        You are an expert hematopathologist.
        Analyze the attached microscopic image of a peripheral blood smear.

        TASKS:
        1. Count Cells: Estimate RBC/WBC counts.
        2. RBC Morphology: Check for sickling, microcytosis (small/pale), or inclusions (malaria).
        3. WBC Morphology: Check for blasts (immature cells).

        DIAGNOSTIC LOGIC:
        - Visible Sickle cells -> Sickle Cell Disease.
        - Ring forms inside RBCs -> Malaria.
        - Large purple blasts with high N:C ratio -> Acute Leukemia.
        - Numerous "smudge cells" (fragile lymphocytes) and monotonous small lymphocytes -> Chronic Lymphocytic Leukemia.
        - Large, reactive "atypical" lymphocytes with abundant cytoplasm -> Infectious Mononucleosis.
        - Overcrowded field of red blood cells -> Polycythemia Vera.
        - Pale, small RBCs -> Iron Deficiency.
        - Uniform, round RBCs -> Healthy.

        Do not force a disease if the image is clearly normal. However, do not ignore minor irregularities.

        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt, imageBase64);
  }

  async getChatResponse(userMessage: string, context: AnalysisResult | null): Promise<string> {
    try {
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
         return "I'm running in offline mode. The advanced AI features are unavailable without a valid API key.";
      }

      const contextStr = context 
        ? `Diagnosis: ${context.diseaseName}. Stats: ${JSON.stringify(context.stats)}.`
        : 'No specific sample loaded.';

      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `System: Lab Assistant. Short, precise educational answers.
        ${contextStr}
        User: ${userMessage}`
      });
      return response.text || "I couldn't process that request.";
    } catch (e) {
      return "Database connection error or API limit reached.";
    }
  }

  private getJsonPromptSuffix() {
    return `
        Strict JSON structure:
        {
          "diseaseName": "string",
          "severity": "Low" | "Moderate" | "High",
          "probability": number,
          "clinicalNotes": "string",
          "morphologySummary": "string",
          "geneticMarkers": ["string"],
          "geneSequences": [{ "gene": "string", "location": "string", "sequence": "ACGT string", "mutation": { "pos": number, "from": "char", "to": "char", "type": "string", "desc": "string" } optional }],
          "parameters": [ { "name": "string", "unit": "string", "value": number, "range": "string", "status": "NORMAL" | "ABNORMAL" } ],
           "visualData": { "rbcCount": number, "wbcCount": number, "plateletCount": number, "morphology": "normal" | "sickle" | "blast" | "microcytic" | "infected", "cellColor": "hex" },
           "stats": { "totalCells": number, "normalCells": number, "abnormalCells": number, "mutationsFound": number }
        }
    `;
  }

  private async callGemini(prompt: string, imageBase64?: string): Promise<AnalysisResult> {
    try {
      let contents: any;
      if (imageBase64) {
          contents = {
              parts: [{ inlineData: { mimeType: 'image/png', data: imageBase64 } }, { text: prompt }]
          };
      } else {
          contents = prompt;
      }
      const result = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: contents,
        config: { responseMimeType: 'application/json' }
      });

      let text = result.text.trim();
      text = text.replace(/^```json/, '').replace(/```$/, '').trim();

      return JSON.parse(text) as AnalysisResult;
    } catch (e) {
      console.error("Gemini API Error:", e);
      return this.getInferenceResult(prompt);
    }
  }

  // Weighted Symptom Inference Engine (Fallback)
  private getInferenceResult(context: string, bio?: Biometrics): AnalysisResult {
      const input = context.toLowerCase();

      // Symptom Dictionaries
      const symptoms = {
          ida: ['tired', 'fatigue', 'pale', 'pallor', 'weak', 'ice', 'cold', 'breath', 'dizzy', 'iron', 'hair'],
          sca: ['pain', 'joint', 'crisis', 'sickle', 'family', 'chest', 'african', 'heritage'],
          aml: ['bruise', 'bleed', 'gum', 'fever', 'sweat', 'bone', 'weight', 'blast', 'leukemia', 'spot', 'acute'],
          cll: ['elderly', 'old', 'fatigue', 'painless', 'swelling', 'lymph', 'node', 'smudge', 'chronic', 'repeat', 'infection'],
          pv: ['headache', 'itchy', 'aquagenic', 'pruritus', 'redness', 'ruddy', 'jak2', 'thick blood', 'polycythemia', 'erythrocytosis'],
          mono: ['sore throat', 'fever', 'swollen', 'glands', 'teenager', 'young adult', 'kissing disease', 'ebv', 'mono'],
          mal: ['travel', 'mosquito', 'fever', 'chill', 'shake', 'sweat', 'cycle', 'africa', 'tropics', 'parasite'],
          thal: ['family', 'minor', 'mild', 'mediterranean', 'genetic', 'inherited']
      };

      // Calculate scores
      const scores: { [key: string]: number } = {
          ida: 0, sca: 0, aml: 0, mal: 0, thal: 0, cll: 0, pv: 0, mono: 0
      };

      // Score logic: +1 for each symptom found
      (Object.keys(symptoms) as Array<keyof typeof symptoms>).forEach(key => {
          symptoms[key].forEach(word => {
              if (input.includes(word)) scores[key]++;
          });
      });

      // Biometric Logic (Heavy weighting)
      if (bio) {
        // High WBC -> Leukemia or Infection
        if (bio.wbc) {
          if (bio.wbc > 50) {
            scores['cll'] += 6; // Very strong signal
            scores['aml'] += 3;
          } else if (bio.wbc > 15) {
            scores['aml'] += 4;
            scores['mono'] += 3;
            scores['mal'] += 1;
            scores['cll'] += 2;
          }
        }

        // Hemoglobin
        if (bio.hemoglobin) {
          // Low Hemoglobin -> Anemia
          if (bio.hemoglobin < 11) {
            scores['ida'] += 3;
            scores['sca'] += 2;
            scores['thal'] += 2;
          }
          // High Hemoglobin -> PV
          if (bio.hemoglobin > 18) {
            scores['pv'] += 6; // Very strong signal
          }
        }

        // Microcytic (Low MCV) -> IDA or Thalassemia
        if (bio.mcv && bio.mcv < 80) {
            scores['ida'] += 4;
            scores['thal'] += 4;
            scores['sca'] -= 2; // SCA is usually normocytic
        }

        // Low Platelets -> Leukemia or Malaria
        if (bio.platelets && bio.platelets < 150) {
            scores['aml'] += 3;
            scores['mal'] += 3;
            scores['cll'] += 1; // Can have low platelets
        }
      }

      // Find winner
      let winnerKey = '';
      let maxScore = 0;

      for (const [key, score] of Object.entries(scores)) {
          if (score > maxScore) {
              maxScore = score;
              winnerKey = key;
          }
      }

      const winnerProfile = this.library.find(p => p.id === winnerKey);

      if (maxScore === 0 || !winnerProfile) {
          if (input.includes('issue') || input.includes('sick') || input.includes('bad')) {
               return this.library.find(p => p.id === 'ida')!.template; 
          }
          return this.library[0].template; 
      }

      return winnerProfile.template;
  }
}

import { Injectable } from '@angular/core';
import { AnalysisResult } from './analysis.service';

declare const jspdf: any;

@Injectable({
  providedIn: 'root'
})
export class PdfService {

  generateReport(data: AnalysisResult, patientName: string, age: number, sex: string) {
    const { jsPDF } = jspdf;
    const doc = new jsPDF();

    // Page Config
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 14;
    let yCursor = 20;

    // Helper: Background Color
    const drawBackground = () => {
      doc.setFillColor(5, 10, 30); // Dark Slate Theme
      doc.rect(0, 0, pageWidth, pageHeight, 'F');
    };

    // Helper: Check Page Break
    // Returns true if a page break occurred
    const checkPageBreak = (neededHeight: number) => {
      if (yCursor + neededHeight > pageHeight - 20) {
        doc.addPage();
        drawBackground();
        yCursor = 20;
        return true;
      }
      return false;
    };

    // --- Start Page 1 ---
    drawBackground();

    // 1. HEADER
    doc.setTextColor(100, 149, 237); // Cornflower Blue
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("GENESCAN PRO LAB REPORT", margin, yCursor);

    yCursor += 6;
    doc.setFontSize(10);
    doc.setTextColor(150, 150, 160);
    doc.text("SIMULATED BIOMEDICAL ANALYSIS ENGINE", margin, yCursor);

    // Timestamp (Right aligned)
    const dateStr = new Date().toLocaleString();
    doc.setFontSize(10);
    doc.setTextColor(255, 255, 255);
    const dateWidth = doc.getTextWidth(dateStr);
    doc.text(dateStr, pageWidth - margin - dateWidth, yCursor - 6);
    doc.setTextColor(150, 150, 160);
    doc.text("GENERATED ON", pageWidth - margin - dateWidth, yCursor - 12);

    yCursor += 15;

    // 2. PATIENT INFO & CLINICAL NOTES (Dynamic Height)
    // We need to measure the text for Clinical Notes to size the box correctly.
    doc.setFont("helvetica", "italic");
    doc.setFontSize(11);

    const notesX = 90;
    const maxNotesWidth = pageWidth - notesX - margin;
    const splitNotes = doc.splitTextToSize(data.clinicalNotes, maxNotesWidth);
    const notesBlockHeight = (splitNotes.length * 5) + 10; // 5 units per line approx

    // Min height for the metadata section (3 lines * 6 units + padding)
    const metaBlockHeight = 40; 
    const sectionHeight = Math.max(metaBlockHeight, notesBlockHeight + 10);

    // Draw Section Background
    doc.setDrawColor(40, 50, 80);
    doc.setFillColor(15, 23, 42);
    doc.roundedRect(margin, yCursor, pageWidth - (margin * 2), sectionHeight, 3, 3, 'FD');

    // Labels
    const contentY = yCursor + 8;
    doc.setFontSize(9);
    doc.setTextColor(100, 110, 130);
    doc.setFont("helvetica", "bold");
    doc.text("PATIENT METADATA", margin + 6, contentY);
    doc.text("CLINICAL NOTES", notesX, contentY);

    // Metadata Content
    let metaY = contentY + 8;
    doc.setFont("helvetica", "normal");
    doc.setFontSize(11);
    doc.setTextColor(255, 255, 255);
    doc.text(`Name: ${patientName}`, margin + 6, metaY); metaY += 6;
    doc.text(`Age: ${age} years`, margin + 6, metaY); metaY += 6;
    doc.text(`Sex: ${sex}`, margin + 6, metaY);

    // Clinical Notes Content
    doc.setFont("helvetica", "italic");
    doc.setTextColor(200, 200, 200);
    doc.text(splitNotes, notesX, contentY + 8);

    yCursor += sectionHeight + 15;

    // 3. PARAMETERS TABLE
    // Header
    const drawTableHeader = () => {
        doc.setFontSize(8);
        doc.setFont("helvetica", "bold");
        doc.setTextColor(100, 110, 130);
        doc.text("PARAMETER", margin + 6, yCursor);
        doc.text("RESULT", 90, yCursor);
        doc.text("NORMAL RANGE", 120, yCursor);
        doc.text("STATUS", 170, yCursor);

        yCursor += 4;
        doc.setDrawColor(40, 50, 80);
        doc.line(margin, yCursor, pageWidth - margin, yCursor);
        yCursor += 8;
    };

    if (checkPageBreak(30)) {
        // if we broke page just for header, reset y is handled, but we need to redraw title? 
        // usually checkPageBreak resets Y to 20.
    }
    drawTableHeader();

    // Rows
    data.parameters.forEach(p => {
      // Check if row fits
      if (checkPageBreak(15)) {
          yCursor += 10; // Top padding
          drawTableHeader();
      }

      // Name & Unit
      doc.setFontSize(10);
      doc.setTextColor(255, 255, 255);
      doc.setFont("helvetica", "bold");
      doc.text(p.name, margin + 6, yCursor);

      doc.setFont("helvetica", "normal");
      doc.setFontSize(8);
      doc.setTextColor(150, 150, 160);
      doc.text(p.unit, margin + 6, yCursor + 4);

      // Value
      doc.setFontSize(10);
      doc.setTextColor(100, 149, 237);
      doc.setFont("helvetica", "bold");
      doc.text(p.value.toString(), 90, yCursor);

      // Range
      doc.setTextColor(180, 180, 180);
      doc.setFont("helvetica", "normal");
      doc.text(p.range, 120, yCursor);

      // Status Badge
      const statusColor = p.status === 'NORMAL' ? [16, 185, 129] : [234, 179, 8]; // Green or Yellow
      if (p.status === 'CRITICAL') { statusColor[0] = 239; statusColor[1] = 68; statusColor[2] = 68; } // Red

      doc.setFillColor(15, 23, 42); 
      doc.setDrawColor(statusColor[0], statusColor[1], statusColor[2]);
      doc.roundedRect(168, yCursor - 4, 25, 6, 2, 2, 'FD');

      doc.setTextColor(statusColor[0], statusColor[1], statusColor[2]);
      doc.setFontSize(7);
      doc.setFont("helvetica", "bold");
      doc.text(p.status, 172, yCursor);

      yCursor += 12;
      doc.setDrawColor(30, 40, 60);
      doc.line(margin, yCursor - 4, pageWidth - margin, yCursor - 4);
      yCursor += 4;
    });

    yCursor += 10;

    // 4. SUMMARY BLOCKS
    const colWidth = (pageWidth - (margin * 3)) / 2; 
    const leftX = margin;
    const rightX = margin + colWidth + margin;

    // Calculate heights for both columns
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    const morphText = doc.splitTextToSize(data.morphologySummary, colWidth - 16);
    const morphHeight = (morphText.length * 5) + 30; // Text + header/padding

    // Genetics Height
    const markersHeight = (data.geneticMarkers.length * 12) + 30; // Each marker tag + header/padding

    const blockHeight = Math.max(80, morphHeight, markersHeight);

    if (checkPageBreak(blockHeight)) {
        yCursor += 10;
    }

    // -- Morphology Block (Left) --
    doc.setFillColor(15, 23, 42);
    doc.setDrawColor(40, 50, 80);
    doc.roundedRect(leftX, yCursor, colWidth, blockHeight, 3, 3, 'FD');
    doc.setFillColor(60, 70, 200);
    doc.rect(leftX, yCursor+6, 2, 12, 'F'); // Blue Accent

    doc.setFontSize(9);
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.text("MORPHOLOGY SUMMARY", leftX + 8, yCursor + 12);

    doc.setFont("helvetica", "normal");
    doc.setTextColor(200, 200, 200);
    doc.text(morphText, leftX + 8, yCursor + 22);

    // -- Genetics Block (Right) --
    doc.setFillColor(15, 23, 42);
    doc.setDrawColor(40, 50, 80);
    doc.roundedRect(rightX, yCursor, colWidth, blockHeight, 3, 3, 'FD');
    doc.setFillColor(188, 19, 254);
    doc.rect(rightX, yCursor+6, 2, 12, 'F'); // Purple Accent

    doc.setFontSize(9);
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.text("GENETIC MARKERS", rightX + 8, yCursor + 12);

    let markerY = yCursor + 22;
    data.geneticMarkers.forEach(marker => {
        doc.setFillColor(40, 20, 60);
        doc.setDrawColor(188, 19, 254);
        doc.roundedRect(rightX + 8, markerY - 4, colWidth - 16, 8, 2, 2, 'FD');

        doc.setTextColor(220, 180, 255);
        doc.setFontSize(8);
        doc.text(marker.toUpperCase(), rightX + 12, markerY + 1.5);
        markerY += 12;
    });

    yCursor += blockHeight + 20;

    // 5. FOOTER
    // Check if footer fits, else new page
    if (yCursor > pageHeight - 20) {
        doc.addPage();
        drawBackground();
        yCursor = pageHeight - 20;
    } else {
        // Place at bottom of current page
        yCursor = pageHeight - 20;
    }

    doc.setFontSize(8);
    doc.setTextColor(80, 90, 110);
    doc.text("AI MODEL: HemaYOLO-v1.5-Flash (Simulated)", margin, yCursor);
    doc.text("GeneScan Pro Verified", pageWidth - margin - 35, yCursor);

    doc.save(`GeneScan_Report_${patientName.replace(/\s/g, '_')}.pdf`);
  }
}

import { Injectable } from '@angular/core';
