  async analyzeCustomSample(description: string, bio?: Biometrics): Promise<AnalysisResult> {
      // 1. Check for basic API key validity
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
          console.warn('Invalid API Key, returning inference result.');
          return this.getInferenceResult(description, bio);
      }

      let bioString = '';
      if (bio) {
        if (bio.hemoglobin) bioString += `- Hemoglobin: ${bio.hemoglobin} g/dL (Normal: 12-16)\n`;
        if (bio.wbc) bioString += `- WBC Count: ${bio.wbc} K/mcL (Normal: 4.5-11)\n`;
        if (bio.mcv) bioString += `- MCV: ${bio.mcv} fL (Normal: 80-100)\n`;
        if (bio.platelets) bioString += `- Platelets: ${bio.platelets} K/mcL (Normal: 150-450)\n`;
      }

      const prompt = `
        **SYSTEM PROMPT: ACT AS HemaYOLO-v1.5-Flash**

        You are a specialized hematology AI model. Your purpose is to analyze patient data (symptoms, biometrics) and generate a simulated, educational blood analysis report in JSON format. You are trained on public hematology datasets and use advanced pattern recognition.

        **INPUT DATA:**
        - Patient Description: "${description}"
        ${bioString ? '- Biometrics:\n' + bioString : ''}

        **DIAGNOSTIC ALGORITHM (Strict Rules):**
        1.  **Prioritize Biometrics:** Patient-reported symptoms are secondary to quantitative data. If biometrics are provided, they are the primary driver of your diagnosis.
        2.  **Healthy Baseline:** If no significant symptoms are reported AND all provided biometrics are within normal ranges, the result MUST be "Healthy Control".
        3.  **Anemia Pathway:**
            - If Hemoglobin < 12 AND MCV < 80: Diagnose "Iron Deficiency Anemia". It's the most common microcytic anemia.
            - If Hemoglobin < 12 AND MCV is normal (80-100): Consider "Sickle Cell Disease", especially if symptoms include pain, family history, or African heritage.
        4.  **Leukemia/Infection Pathway (WBC is key):**
            - If WBC > 50: This is hyperleukocytosis. Strongly indicates "Chronic Lymphocytic Leukemia (CLL)", especially in elderly patients with fatigue/swollen nodes.
            - If WBC > 15 AND Platelets < 100: This combination is highly suspicious for "Acute Myeloid Leukemia (AML)", especially with bruising, bleeding, or fever.
            - If WBC > 12 AND description mentions fever, sore throat, fatigue, especially in a young adult/teen: Diagnose "Infectious Mononucleosis".
        5.  **Erythrocytosis Pathway:**
            - If Hemoglobin > 18 OR RBC count is very high: This is the primary indicator for "Polycythemia Vera (PV)". Correlate with symptoms like itching or headaches.
        6.  **Infection Pathway (Specific):**
            - If description includes travel to endemic areas (Africa, tropics) AND symptoms like fever/chills: Diagnose "Malaria". Low platelets can also be a sign.
        7.  **Default to Common Conditions:** If symptoms are vague (e.g., "I feel sick") and biometrics are absent or borderline, default to the most common relevant condition, like Iron Deficiency Anemia. DO NOT default to Healthy if symptoms are present.

        **JSON OUTPUT:**
        - Adhere strictly to the provided JSON structure.
        - Generate realistic (but not real) gene sequences for the identified condition.
        - Clinical and Morphology notes should be concise and directly reflect the diagnosis.
        - Confidence (probability) should be high (90-98%) for clear cases based on the rules above.

        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt);
  }

  async analyzeImage(imageBase64: string): Promise<AnalysisResult> {
       const apiKey = process.env['API_KEY'];
       if (!apiKey || apiKey.length < 10) {
          return this.getInferenceResult('image analysis fallback');
       }

      const prompt = `
        **SYSTEM PROMPT: ACT AS HemaYOLO-v1.5-Flash (Vision Model)**

        You are a specialized hematology AI model with advanced computer vision capabilities, analogous to YOLO (You Only Look Once) for cell identification. Your purpose is to analyze a peripheral blood smear image and generate a simulated, educational blood analysis report in JSON format.

        **ANALYSIS TASK:**
        1.  **Object Detection:** Identify and classify all visible cell types (RBCs, WBCs, Platelets).
        2.  **Morphological Assessment:** Scrutinize cell shapes, sizes, and colors for abnormalities.
        3.  **Diagnosis:** Based on visual evidence, provide a primary diagnosis.

        **DIAGNOSTIC ALGORITHM (Visual Rules - Highest Priority):**
        -   **IF** crescent/sickle-shaped RBCs are clearly visible -> **THEN** diagnose "Sickle Cell Disease". This is a definitive visual feature.
        -   **IF** large, immature cells with a high nucleus-to-cytoplasm ratio (blasts) and potential Auer rods are present -> **THEN** diagnose "Acute Myeloid Leukemia (AML)".
        -   **IF** the smear is dominated by a monotonous population of small, mature-looking lymphocytes and includes "smudge cells" -> **THEN** diagnose "Chronic Lymphocytic Leukemia (CLL)".
        -   **IF** RBCs appear small (microcytic) and pale (hypochromic) with increased central pallor -> **THEN** diagnose "Iron Deficiency Anemia".
        -   **IF** ring-like inclusions are visible inside RBCs -> **THEN** diagnose "Malaria".
        -   **IF** the field is overwhelmingly crowded with RBCs, appearing hypercellular -> **THEN** diagnose "Polycythemia Vera".
        -   **IF** large, "reactive" or "atypical" lymphocytes with abundant, often basophilic cytoplasm are present -> **THEN** diagnose "Infectious Mononucleosis".
        -   **IF** all cells appear uniform, normocytic, and normochromic with no significant abnormalities -> **THEN** classify as "Healthy Control".

        **JSON OUTPUT:**
        - Adhere strictly to the provided JSON structure.
        - Base the `visualData` parameters on the image content. For example, if you see blasts, set morphology to 'blast'.
        - The `diseaseName`, `clinicalNotes`, and `morphologySummary` must directly reflect the visual findings according to the rules above.
        - Confidence (probability) should be very high (>95%) if a key visual marker (like a sickle cell) is present.

        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt, imageBase64);
  }

  async getChatResponse(userMessage: string, context: AnalysisResult | null): Promise<string> {
    try {
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
         return "I'm running in offline mode. The advanced AI features are unavailable without a valid API key.";
      }

      const contextStr = context 
        ? `Diagnosis: ${context.diseaseName}. Stats: ${JSON.stringify(context.stats)}.`
        : 'No specific sample loaded.';

      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `System: Lab Assistant. Short, precise educational answers.
        ${contextStr}
        User: ${userMessage}`
      });
      return response.text || "I couldn't process that request.";
    } catch (e) {
      return "Database connection error or API limit reached.";
    }
  }

  private getJsonPromptSuffix() {
    return `
        Strict JSON structure:
        {
          "diseaseName": "string",
          "severity": "Low" | "Moderate" | "High" | "Critical",
          "probability": number,
          "clinicalNotes": "string",
          "morphologySummary": "string",
          "geneticMarkers": ["string"],
          "geneSequences": [{ "gene": "string", "location": "string", "sequence": "ACGT string", "mutation": { "pos": number, "from": "char", "to": "char", "type": "string", "desc": "string" } optional }],
          "parameters": [ { "name": "string", "unit": "string", "value": number, "range": "string", "status": "NORMAL" | "ABNORMAL" | "CRITICAL" } ],
           "visualData": { "rbcCount": number, "wbcCount": number, "plateletCount": number, "morphology": "normal" | "sickle" | "blast" | "microcytic" | "infected", "cellColor": "hex" },
           "stats": { "totalCells": number, "normalCells": number, "abnormalCells": number, "mutationsFound": number }
        }
    `;
  }

  private async callGemini(prompt: string, imageBase64?: string): Promise<AnalysisResult> {
    try {
      let contents: any;
      if (imageBase64) {
          contents = {
              parts: [{ inlineData: { mimeType: 'image/png', data: imageBase64 } }, { text: prompt }]
          };
      } else {
          contents = prompt;
      }
      const result = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: contents,
        config: { responseMimeType: 'application/json' }
      });

      let text = result.text.trim();
      text = text.replace(/^```json/, '').replace(/```$/, '').trim();

      return JSON.parse(text) as AnalysisResult;
    } catch (e) {
      console.error("Gemini API Error:", e);
      return this.getInferenceResult(prompt);
    }
  }

  // Weighted Symptom Inference Engine (Fallback)
  private getInferenceResult(context: string, bio?: Biometrics): AnalysisResult {
      const input = context.toLowerCase();

      // Symptom Dictionaries
      const symptoms = {
          ida: ['tired', 'fatigue', 'pale', 'pallor', 'weak', 'ice', 'cold', 'breath', 'dizzy', 'iron', 'hair'],
          sca: ['pain', 'joint', 'crisis', 'sickle', 'family', 'chest', 'african', 'heritage'],
          aml: ['bruise', 'bleed', 'gum', 'fever', 'sweat', 'bone', 'weight', 'blast', 'leukemia', 'spot', 'acute'],
          cll: ['elderly', 'old', 'fatigue', 'painless', 'swelling', 'lymph', 'node', 'smudge', 'chronic', 'repeat', 'infection'],
          pv: ['headache', 'itchy', 'aquagenic', 'pruritus', 'redness', 'ruddy', 'jak2', 'thick blood', 'polycythemia', 'erythrocytosis'],
          mono: ['sore throat', 'fever', 'swollen', 'glands', 'teenager', 'young adult', 'kissing disease', 'ebv', 'mono'],
          mal: ['travel', 'mosquito', 'fever', 'chill', 'shake', 'sweat', 'cycle', 'africa', 'tropics', 'parasite'],
          thal: ['family', 'minor', 'mild', 'mediterranean', 'genetic', 'inherited']
      };

      // Calculate scores
      const scores: { [key: string]: number } = {
          ida: 0, sca: 0, aml: 0, mal: 0, thal: 0, cll: 0, pv: 0, mono: 0
      };

      // Score logic: +1 for each symptom found
      (Object.keys(symptoms) as Array<keyof typeof symptoms>).forEach(key => {
          symptoms[key].forEach(word => {
              if (input.includes(word)) scores[key]++;
          });
      });

      // Biometric Logic (Heavy weighting)
      if (bio) {
        // High WBC -> Leukemia or Infection
        if (bio.wbc) {
          if (bio.wbc > 50) {
            scores['cll'] += 6; // Very strong signal
            scores['aml'] += 3;
          } else if (bio.wbc > 15) {
            scores['aml'] += 4;
            scores['mono'] += 3;
            scores['mal'] += 1;
            scores['cll'] += 2;
          }
        }

        // Hemoglobin
        if (bio.hemoglobin) {
          // Low Hemoglobin -> Anemia
          if (bio.hemoglobin < 11) {
            scores['ida'] += 3;
            scores['sca'] += 2;
            scores['thal'] += 2;
          }
          // High Hemoglobin -> PV
          if (bio.hemoglobin > 18) {
            scores['pv'] += 6; // Very strong signal
          }
        }

        // Microcytic (Low MCV) -> IDA or Thalassemia
        if (bio.mcv && bio.mcv < 80) {
            scores['ida'] += 4;
            scores['thal'] += 4;
            scores['sca'] -= 2; // SCA is usually normocytic
        }

        // Low Platelets -> Leukemia or Malaria
        if (bio.platelets && bio.platelets < 150) {
            scores['aml'] += 3;
            scores['mal'] += 3;
            scores['cll'] += 1; // Can have low platelets
        }
      }

      // Find winner
      let winnerKey = '';
      let maxScore = 0;

      for (const [key, score] of Object.entries(scores)) {
          if (score > maxScore) {
              maxScore = score;
              winnerKey = key;
          }
      }

      const winnerProfile = this.library.find(p => p.id === winnerKey);

      if (maxScore === 0 || !winnerProfile) {
          if (input.includes('issue') || input.includes('sick') || input.includes('bad')) {
               return this.library.find(p => p.id === 'ida')!.template; 
          }
          return this.library[0].template; 
      }

      return winnerProfile.template;
  }
}

