export interface BloodParameter {
  name: string;
  unit: string;
  value: number | string;
  range: string;
  status: 'NORMAL' | 'ABNORMAL' | 'CRITICAL';
}

export interface GeneSequence {
  gene: string;
  location: string;
  sequence: string;
  mutation?: {
    pos: number;
    from: string;
    to: string;
    type: string;
    desc: string;
  };
}

export interface AnalysisResult {
  diseaseName: string;
  severity: 'Low' | 'Moderate' | 'High' | 'Critical';
  probability: number;
  clinicalNotes: string;
  morphologySummary: string;
  geneticMarkers: string[]; 
  geneSequences: GeneSequence[]; 
  parameters: BloodParameter[];
  visualData: {
    rbcCount: number;
    wbcCount: number;
    plateletCount: number;
    morphology: 'normal' | 'sickle' | 'blast' | 'microcytic' | 'infected';
    cellColor: string;
  };
  stats: {
    totalCells: number;
    normalCells: number;
    abnormalCells: number;
    mutationsFound: number;
  }
}

export interface DiseaseProfile {
  id: string;
  name: string;
  description: string;
  type: 'Anemia' | 'Leukemia' | 'Infection' | 'Genetic' | 'Healthy';
  template: AnalysisResult;
}

export interface Biometrics {
  hemoglobin?: number;
  wbc?: number;
  platelets?: number;
  mcv?: number;
}

