  async analyzeCustomSample(description: string, bio?: Biometrics): Promise<AnalysisResult> {
      // 1. Check for basic API key validity
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
          console.warn('Invalid API Key, returning inference result.');
          return this.getInferenceResult(description, bio);
      }

      let bioString = '';
      if (bio) {
        if (bio.hemoglobin) bioString += `- Hemoglobin: ${bio.hemoglobin} g/dL (Normal: 12-16)\n`;
        if (bio.wbc) bioString += `- WBC Count: ${bio.wbc} K/mcL (Normal: 4.5-11)\n`;
        if (bio.mcv) bioString += `- MCV: ${bio.mcv} fL (Normal: 80-100)\n`;
        if (bio.platelets) bioString += `- Platelets: ${bio.platelets} K/mcL (Normal: 150-450)\n`;
      }

      const prompt = `
        **SYSTEM PROMPT: ACT AS HemaYOLO-v2.0-Pro**

        You are a specialized hematology AI model. Your purpose is to analyze patient data (symptoms, biometrics) and generate a simulated, educational blood analysis report in JSON format. Your goal is to synthesize all available information to form a general diagnostic impression, not to follow rigid rules that lead to a default diagnosis.

        **INPUT DATA:**
        - Patient Description: "${description}"
        ${bioString ? '- Biometrics:\n' + bioString : ''}

        **ANALYTICAL METHODOLOGY:**
        Instead of fixed rules, use the following correlational logic to arrive at a diagnosis. Weigh all factors.

        1.  **Evaluate Patient Context:** Age, acuity of symptoms (sudden vs. chronic), and specific keywords are critical.
            - *Example*: "Fatigue" is a general symptom, but "painless swollen nodes in an elderly patient" is highly specific for CLL. "Sudden bruising and bleeding" is highly specific for an acute process like AML.

        2.  **Correlate Biometrics with Symptoms:**
            -   **Anemia (Low Hemoglobin):**
                -   If MCV is low (<80), strongly suspect **Iron Deficiency Anemia**. If the patient is of Mediterranean descent, also consider **Thalassemia Minor**.
                -   If MCV is normal and symptoms include severe pain or family history, **Sickle Cell Disease** is a primary consideration.
            -   **Leukocytosis (High WBC):**
                -   Extreme elevation (>50k) points towards a chronic leukemia like **CLL**, especially if lymphocytes are the dominant cell type mentioned or implied by symptoms (e.g., swollen nodes).
                -   Moderate elevation (15-40k) with low platelets (<100k) is a red flag for **Acute Myeloid Leukemia (AML)**, particularly with symptoms of bleeding, fever, and bone pain.
                -   Moderate elevation (12-25k) in a younger patient with fever and sore throat is classic for **Infectious Mononucleosis**.
            -   **Erythrocytosis (High Hemoglobin/RBCs):**
                -   Sustained high levels (>18 g/dL) are the hallmark of **Polycythemia Vera**. Correlate with symptoms like aquagenic pruritus (itching after shower) or headaches.
            -   **Travel/Fever Context:**
                -   A history of travel to endemic regions combined with cyclical fevers and chills strongly suggests **Malaria**, which can also present with low platelets and anemia.

        3.  **Synthesize a Conclusion:** Do not simply pick the first match. The final \`diseaseName\` should be the one best supported by the *entire picture*. If data is conflicting or sparse, state this in the \`clinicalNotes\`. Acknowledge the general nature of the findings.

        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt);
  }

  async analyzeImage(imageBase64: string): Promise<AnalysisResult> {
       const apiKey = process.env['API_KEY'];
       if (!apiKey || apiKey.length < 10) {
          return this.getInferenceResult('image analysis fallback');
       }

      const prompt = `
        **SYSTEM PROMPT: ACT AS HemaYOLO-v2.0-Pro (Advanced Vision Model)**

        You are a state-of-the-art hematology AI, specialized in the analysis of peripheral blood micrographs. Your primary function is to identify and interpret morphological findings in the provided image to derive a probable hematological condition. **Your conclusion must be based *exclusively* on the visual evidence in the micrograph.** Do not invent findings or default to a common diagnosis if the evidence is not present. Your output must be a structured JSON report.

        **METHODOLOGY: SYSTEMATIC MICROGRAPH REVIEW**
        Perform the following analysis steps internally. Your JSON output should reflect these findings.

        1.  **Overall Smear Assessment:**
            - Evaluate cellularity (hypo-, normo-, hypercellular). Note stain quality and artifacts.

        2.  **Red Blood Cell (RBC) Morphology:**
            - **Size/Color:** Assess for microcytosis, macrocytosis, and hypochromia.
            - **Shape:** Systematically search for key poikilocytes:
                - **Drepanocytes (Sickle cells):** If present, this is a strong indicator for **Sickle Cell Disease**.
                - **Schistocytes (Fragments):** Suggests microangiopathic hemolysis.
            - **Inclusions:** Look for intracellular parasites (ring forms) which indicate **Malaria**.

        3.  **White Blood Cell (WBC) Morphology & Differential:**
            - **Lineage and Maturity:** The most critical step. Are there immature **blasts**? A significant presence of blasts, especially with **Auer rods**, is pathognomonic for **Acute Myeloid Leukemia (AML)**.
            - **Lymphocyte Population:** Is there a monotonous sea of small, mature-looking lymphocytes? Are there numerous **smudge cells**? This combination is the classic presentation of **Chronic Lymphocytic Leukemia (CLL)**. Conversely, are there large, **reactive/atypical lymphocytes**? This points to **Infectious Mononucleosis**.

        4.  **Platelet Assessment:**
            - Estimate if platelets are decreased, normal, or increased.

        **DIAGNOSTIC SYNTHESIS:**
        - The \`morphologySummary\` must describe the key visual findings (e.g., "Predominance of blasts with visible Auer rods.").
        - The \`clinicalNotes\` must explicitly link those findings to the diagnosis (e.g., "The presence of circulating blasts with Auer rods is diagnostic for Acute Myeloid Leukemia.").
        - The \`diseaseName\` must be the direct conclusion from this synthesis. **If no definitive features are seen, classify as 'Healthy Control' or describe the non-specific findings accurately.**

        ${this.getJsonPromptSuffix()}
      `;
      return this.callGemini(prompt, imageBase64);
  }

  async getChatResponse(userMessage: string, context: AnalysisResult | null): Promise<string> {
    try {
      const apiKey = process.env['API_KEY'];
      if (!apiKey || apiKey.length < 10) {
         return "I'm running in offline mode. The advanced AI features are unavailable without a valid API key.";
      }

      const contextStr = context 
        ? `Diagnosis: ${context.diseaseName}. Stats: ${JSON.stringify(context.stats)}.`
        : 'No specific sample loaded.';

      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `System: Lab Assistant. Short, precise educational answers.
        ${contextStr}
        User: ${userMessage}`
      });
      return response.text || "I couldn't process that request.";
    } catch (e) {
      return "Database connection error or API limit reached.";
    }
  }

  private getJsonPromptSuffix() {
    // FIX: Removed the explicit JSON structure from the prompt. 
    // The response schema is now handled programmatically, which is more robust.
    return `
        **JSON OUTPUT:**
        - Adhere strictly to the provided JSON structure schema.
        - Generate realistic (but not real) gene sequences for the identified condition.
        - Clinical and Morphology notes should be concise and directly reflect the diagnosis.
        - Confidence (probability) should be high (90-98%) for clear cases based on the rules above.
    `;
  }

  // FIX: Added a strict schema for the AnalysisResult to ensure the Gemini API returns valid JSON.
  private analysisResultSchema = {
    type: Type.OBJECT,
    properties: {
      diseaseName: { type: Type.STRING },
      severity: { type: Type.STRING },
      probability: { type: Type.NUMBER },
      clinicalNotes: { type: Type.STRING },
      morphologySummary: { type: Type.STRING },
      geneticMarkers: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
      },
      geneSequences: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            gene: { type: Type.STRING },
            location: { type: Type.STRING },
            sequence: { type: Type.STRING },
            mutation: {
              type: Type.OBJECT,
              properties: {
                pos: { type: Type.INTEGER },
                from: { type: Type.STRING },
                to: { type: Type.STRING },
                type: { type: Type.STRING },
                desc: { type: Type.STRING },
              },
              required: ['pos', 'from', 'to', 'type', 'desc']
            },
          },
          required: ['gene', 'location', 'sequence']
        },
      },
      parameters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            unit: { type: Type.STRING },
            value: { type: Type.NUMBER },
            range: { type: Type.STRING },
            status: { type: Type.STRING },
          },
          required: ['name', 'unit', 'value', 'range', 'status']
        },
      },
      visualData: {
        type: Type.OBJECT,
        properties: {
          rbcCount: { type: Type.INTEGER },
          wbcCount: { type: Type.INTEGER },
          plateletCount: { type: Type.INTEGER },
          morphology: { type: Type.STRING },
          cellColor: { type: Type.STRING },
        },
        required: ['rbcCount', 'wbcCount', 'plateletCount', 'morphology', 'cellColor']
      },
      stats: {
        type: Type.OBJECT,
        properties: {
          totalCells: { type: Type.INTEGER },
          normalCells: { type: Type.INTEGER },
          abnormalCells: { type: Type.INTEGER },
          mutationsFound: { type: Type.INTEGER },
        },
        required: ['totalCells', 'normalCells', 'abnormalCells', 'mutationsFound']
      },
    },
    required: [
        'diseaseName', 'severity', 'probability', 'clinicalNotes', 'morphologySummary',
        'geneticMarkers', 'geneSequences', 'parameters', 'visualData', 'stats'
    ]
  };

  private async callGemini(prompt: string, imageBase64?: string): Promise<AnalysisResult> {
    try {
      let contents: any;
      if (imageBase64) {
          contents = {
              parts: [{ inlineData: { mimeType: 'image/png', data: imageBase64 } }, { text: prompt }]
          };
      } else {
          contents = prompt;
      }
      // FIX: Updated the Gemini API call to use `responseSchema` for robust and guaranteed JSON output.
      const result = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: contents,
        config: { 
          responseMimeType: 'application/json',
          responseSchema: this.analysisResultSchema 
        }
      });

      const text = result.text.trim();
      // FIX: Removed manual stripping of markdown backticks. `responseSchema` ensures clean JSON output.
      return JSON.parse(text) as AnalysisResult;
    } catch (e) {
      console.error("Gemini API Error:", e);
      return this.getInferenceResult(prompt);
    }
  }

  // Weighted Symptom Inference Engine (Fallback)
  private getInferenceResult(context: string, bio?: Biometrics): AnalysisResult {
      const input = context.toLowerCase();

      // Symptom Dictionaries
      const symptoms = {
          ida: ['tired', 'fatigue', 'pale', 'pallor', 'weak', 'ice', 'cold', 'breath', 'dizzy', 'iron', 'hair'],
          sca: ['pain', 'joint', 'crisis', 'sickle', 'family', 'chest', 'african', 'heritage'],
          aml: ['bruise', 'bleed', 'gum', 'fever', 'sweat', 'bone', 'weight', 'blast', 'leukemia', 'spot', 'acute'],
          cll: ['elderly', 'old', 'fatigue', 'painless', 'swelling', 'lymph', 'node', 'smudge', 'chronic', 'repeat', 'infection'],
          pv: ['headache', 'itchy', 'aquagenic', 'pruritus', 'redness', 'ruddy', 'jak2', 'thick blood', 'polycythemia', 'erythrocytosis'],
          mono: ['sore throat', 'fever', 'swollen', 'glands', 'teenager', 'young adult', 'kissing disease', 'ebv', 'mono'],
          mal: ['travel', 'mosquito', 'fever', 'chill', 'shake', 'sweat', 'cycle', 'africa', 'tropics', 'parasite'],
          thal: ['family', 'minor', 'mild', 'mediterranean', 'genetic', 'inherited']
      };

      // Calculate scores
      const scores: { [key: string]: number } = {
          ida: 0, sca: 0, aml: 0, mal: 0, thal: 0, cll: 0, pv: 0, mono: 0
      };

      // Score logic: +1 for each symptom found
      (Object.keys(symptoms) as Array<keyof typeof symptoms>).forEach(key => {
          symptoms[key].forEach(word => {
              if (input.includes(word)) scores[key]++;
          });
      });

      // Biometric Logic (Heavy weighting)
      if (bio) {
        // High WBC -> Leukemia or Infection
        if (bio.wbc) {
          if (bio.wbc > 50) {
            scores['cll'] += 6; // Very strong signal
            scores['aml'] += 3;
          } else if (bio.wbc > 15) {
            scores['aml'] += 3; // Reduced from 4
            scores['mono'] += 4; // Increased from 3
            scores['mal'] += 1;
            scores['cll'] += 2;
          }
        }

        // Hemoglobin
        if (bio.hemoglobin) {
          // Low Hemoglobin -> Anemia
          if (bio.hemoglobin < 11) {
            scores['ida'] += 3;
            scores['sca'] += 2;
            scores['thal'] += 2;
          }
          // High Hemoglobin -> PV
          if (bio.hemoglobin > 18) {
            scores['pv'] += 6; // Very strong signal
          }
        }

        // Microcytic (Low MCV) -> IDA or Thalassemia
        if (bio.mcv && bio.mcv < 80) {
            scores['ida'] += 4;
            scores['thal'] += 4;
            scores['sca'] -= 2; // SCA is usually normocytic
        }

        // Low Platelets -> Leukemia or Malaria
        if (bio.platelets && bio.platelets < 150) {
            scores['aml'] += 3;
            scores['mal'] += 3;
            scores['cll'] += 2; // Increased from 1
        }
      }

      // Find winner
      let winnerKey = '';
      let maxScore = 0;

      for (const [key, score] of Object.entries(scores)) {
          if (score > maxScore) {
              maxScore = score;
              winnerKey = key;
          }
      }

      const winnerProfile = this.library.find(p => p.id === winnerKey);

      if (maxScore === 0 || !winnerProfile) {
          if (input.includes('issue') || input.includes('sick') || input.includes('bad')) {
               return this.library.find(p => p.id === 'ida')!.template; 
          }
          return this.library[0].template; 
      }

      return winnerProfile.template;
  }
}

import { Component, inject, signal, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AnalysisService, AnalysisResult, DiseaseProfile } from './services/analysis.service';
import { PdfService } from './services/pdf.service';
import { CellCanvasComponent } from './components/cell-canvas.component';
import { ChatAssistantComponent } from './components/chat-assistant.component';
import { FormsModule, ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';

type ViewState = 'LOGIN' | 'DASHBOARD' | 'MANUAL_ENTRY' | 'LOADING';
type UserType = 'PATIENT' | 'DOCTOR';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, CellCanvasComponent, ChatAssistantComponent, FormsModule, ReactiveFormsModule],
  templateUrl: './app.component.html'
})
export class AppComponent implements OnInit {
  private analysisService = inject(AnalysisService);
  private pdfService = inject(PdfService);
  private fb: FormBuilder = inject(FormBuilder);

  viewState = signal<ViewState>('LOGIN');

  // Login Mode Toggle
  loginTab = signal<UserType>('DOCTOR');

  currentProfile = signal<DiseaseProfile | null>(null);
  currentResult = signal<AnalysisResult | null>(null);
  uploadedImage = signal<string | null>(null);

  // Track current user state
  currentUserType = signal<UserType>('DOCTOR');
  currentUserName = signal<string>('');

  // PWA Install State
  installPromptEvent = signal<any>(null);
  showInstallHelp = signal(false);

  patientInfo = { name: '', id: '', age: 0, sex: 'Unknown' };

  // Staff Login Form
  staffForm = this.fb.group({
    username: ['', Validators.required],
    password: ['', Validators.required]
  });

  // Patient Login Form
  patientForm = this.fb.group({
    fullName: ['', Validators.required],
    patientId: ['', [Validators.required, Validators.minLength(4)]] // UID
  });

  // Manual Analysis Form
  manualForm = this.fb.group({
    description: [''],
    image: [null],
    age: [35, [Validators.required, Validators.min(0)]],
    sex: ['Female', Validators.required],
    // Biometrics (Optional)
    hemoglobin: [null as number | null],
    wbc: [null as number | null],
    platelets: [null as number | null],
    mcv: [null as number | null],
  });

  availableDiseases = this.analysisService.getLibrary();

  ngOnInit() {
    this.currentProfile.set(this.availableDiseases[2]); 
    this.currentResult.set(this.availableDiseases[2].template);

    // Listen for PWA Install Prompt (Chrome/Edge/Android)
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      this.installPromptEvent.set(e);
    });
  }

  // --- Auth Methods ---

  handlePatientLogin() {
    if (this.patientForm.valid) {
      const { fullName, patientId } = this.patientForm.value;

      this.currentUserType.set('PATIENT');
      this.currentUserName.set(fullName || 'Patient');

      // Initialize patient info
      this.patientInfo = {
        name: fullName || 'Patient',
        id: patientId || '0000',
        age: 0,
        sex: 'Unknown'
      };

      this.enterManualMode();
    }
  }

  continueAsGuest() {
    // Try to grab name from input if available
    let guestName = this.patientForm.value.fullName?.trim();

    // If empty, prompt the user
    if (!guestName) {
        const input = prompt("Please enter a Patient Name for the session report (Optional):");
        guestName = input ? input.trim() : null;
    }

    // Default if still empty
    const finalName = guestName || 'Guest User';

    this.currentUserType.set('PATIENT');
    this.currentUserName.set(finalName);

    // Initialize patient info defaults for guest
    this.patientInfo = {
      name: finalName,
      id: 'GUEST-ACCESS',
      age: 30, 
      sex: 'Unknown'
    };

    this.enterManualMode();
  }

  handleStaffLogin() {
    if (this.staffForm.valid) {
      const { username, password } = this.staffForm.value;

      if (password === 'Shiv@.pm2010') {
        this.currentUserType.set('DOCTOR');
        this.currentUserName.set(`Dr. ${username || 'User'}`);
        this.viewState.set('DASHBOARD');
      } else {
        alert('Access Denied: Incorrect Access Key.');
        this.staffForm.get('password')?.reset();
      }
    }
  }

  signOut() {
    this.viewState.set('LOGIN');
    this.currentUserType.set('DOCTOR');
    this.currentUserName.set('');
    this.staffForm.reset();
    this.patientForm.reset();
  }

  // --- PWA Method ---
  installApp() {
    const prompt = this.installPromptEvent();
    if (prompt) {
      // Browser supports automatic install prompt
      prompt.prompt();
      prompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          this.installPromptEvent.set(null);
        }
      });
    } else {
      // Browser (like iOS Safari) needs manual instructions
      this.showInstallHelp.set(true);
    }
  }

  closeInstallHelp() {
    this.showInstallHelp.set(false);
  }

  // --- App Logic ---

  enterManualMode() {
    this.viewState.set('MANUAL_ENTRY');
    this.uploadedImage.set(null);
    this.manualForm.patchValue({
        description: '',
        age: 35,
        sex: 'Female',
        hemoglobin: null,
        wbc: null,
        platelets: null,
        mcv: null
    });
    this.currentProfile.set(null); // Reset dropdown
  }

  goBack() {
    if (this.currentResult()) {
        this.viewState.set('DASHBOARD');
    } else {
        alert("Please complete a scan first.");
    }
  }

  loadSample(profile: DiseaseProfile) {
    this.currentProfile.set(profile);
    this.currentResult.set(profile.template);
  }

  onProfileChange(selection: DiseaseProfile | 'CUSTOM' | null) {
    if (selection === 'CUSTOM') {
      this.enterManualMode();
    } else if (selection) {
      this.loadSample(selection);
      this.viewState.set('DASHBOARD');
    }
  }

  onFileSelected(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => this.uploadedImage.set(reader.result as string);
      reader.readAsDataURL(file);
    }
  }

  async runManualAnalysis() {
    this.viewState.set('LOADING');
    try {
        const formVal = this.manualForm.value;
        const desc = formVal.description || '';
        const image = this.uploadedImage();

        const biometrics = {
          hemoglobin: formVal.hemoglobin ?? undefined,
          wbc: formVal.wbc ?? undefined,
          platelets: formVal.platelets ?? undefined,
          mcv: formVal.mcv ?? undefined
        };

        this.patientInfo = {
            ...this.patientInfo,
            age: formVal.age || 0,
            sex: formVal.sex || 'Unknown'
        };

        let result: AnalysisResult;

        if (image) {
            const base64 = image.split(',')[1];
            result = await this.analysisService.analyzeImage(base64);
        } else {
            result = await this.analysisService.analyzeCustomSample(desc || 'Standard blood sample', biometrics);
        }

        this.currentResult.set(result);
        this.currentProfile.set({
          id: 'custom',
          name: image ? 'Image Scan Analysis' : 'Custom Description',
          description: image ? 'Analysis generated from uploaded microscopic image.' : desc,
          type: 'Healthy', 
          template: result
        });
        this.viewState.set('DASHBOARD');
    } catch (e) {
        console.error(e);
        this.viewState.set('MANUAL_ENTRY');
        alert("Analysis failed. Please try again.");
    }
  }

  downloadReport() {
    const result = this.currentResult();
    if (result) {
      this.pdfService.generateReport(result, this.patientInfo.name, this.patientInfo.age, this.patientInfo.sex);
    }
  }

  getDnaSegments(sequence: string, mutationPos?: number) {
    return sequence.split('').map((char, index) => {
      const isMutated = mutationPos && Math.abs(index - mutationPos) <= 0; 

      let colorClass = 'text-slate-400';
      if (char === 'A') colorClass = 'text-[#4ADE80]'; // Green
      if (char === 'T') colorClass = 'text-[#60A5FA]'; // Blue
      if (char === 'C') colorClass = 'text-[#F87171]'; // Red
      if (char === 'G') colorClass = 'text-[#FACC15]'; // Yellow

      if (isMutated) {
          colorClass = 'text-white bg-yellow-600 px-0.5 rounded font-bold animate-pulse';
      }

      return { char, colorClass };
    });
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from '@google/genai';

export interface HealthData {
  hr: number;       // Heart Rate (beats per minute)
  hrv: number;      // Heart Rate Variability (ms)
  mood: number;     // Self-reported mood (1-10)
  sleep: number;    // Sleep duration (hours)
}

export interface BaselineData {
  hr: number;
  hrv: number;
  sleep: number;
}

export interface AnomalyScoreResult {
  score: number; // 0 to 1
  level: 'Stable' | 'Mild Deviation' | 'Moderate Pattern' | 'Significant Deviation';
  contributors: {
    hr: number;
    hrv: number;
    mood: number;
    sleep: number;
  };
  aiExplanation: string;
  recommendations: string[];
}

@Injectable({
  providedIn: 'root'
})
export class HealthMonitoringService {
  private ai: GoogleGenAI;
  private weights = {
    hr: 0.20,
    hrv: 0.40,
    mood: 0.15,
    sleep: 0.25,
  };

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  calculateAnomalyScore(current: HealthData, baseline: BaselineData): Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'> {
    // 1. Calculate individual deviation scores (D_x)
    const d_hr = Math.min(1, Math.abs(current.hr - baseline.hr) / (baseline.hr * 0.5));
    const d_hrv = Math.min(1, Math.max(0, (baseline.hrv - current.hrv) / baseline.hrv));
    const d_mood = (10 - current.mood) / 9;
    const d_sleep = Math.min(1, Math.max(0, (baseline.sleep - current.sleep) / baseline.sleep));

    // 2. Calculate weighted contributions
    const contrib_hr = this.weights.hr * d_hr;
    const contrib_hrv = this.weights.hrv * d_hrv;
    const contrib_mood = this.weights.mood * d_mood;
    const contrib_sleep = this.weights.sleep * d_sleep;

    // 3. Calculate final Anomaly Score (AS)
    const score = contrib_hr + contrib_hrv + contrib_mood + contrib_sleep;

    // 4. Classify anomaly level
    let level: AnomalyScoreResult['level'];
    if (score < 0.20) level = 'Stable';
    else if (score < 0.40) level = 'Mild Deviation';
    else if (score < 0.60) level = 'Moderate Pattern';
    else level = 'Significant Deviation';

    return {
      score: Math.round(score * 1000) / 1000, // Round to 3 decimal places
      level,
      contributors: {
        hr: Math.round(contrib_hr * 100),
        hrv: Math.round(contrib_hrv * 100),
        mood: Math.round(contrib_mood * 100),
        sleep: Math.round(contrib_sleep * 100),
      }
    };
  }

  async getAiInterpretation(result: Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'>, userName: string): Promise<{aiExplanation: string, recommendations: string[]}> {
    const apiKey = process.env['API_KEY'];
    if (!apiKey || apiKey.length < 10) {
      return this.getOfflineInterpretation(result.level);
    }

    const prompt = this.constructGeminiPrompt(result, userName);

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      const text = response.text;

      // Extract JSON from the response
      const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/);
      if (jsonMatch && jsonMatch[1]) {
        const parsed = JSON.parse(jsonMatch[1]);
        return {
           aiExplanation: parsed.explanation,
           recommendations: parsed.recommendations
        };
      } else {
        return this.getOfflineInterpretation(result.level);
      }
    } catch (error) {
      console.error("Gemini API error:", error);
      return this.getOfflineInterpretation(result.level);
    }
  }

  private constructGeminiPrompt(result: Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'>, userName: string): string {
    return `
      **SYSTEM PROMPT: ACT AS A PREVENTATIVE WELLNESS AI FOR A TEENAGER**

      **Objective:** Analyze physiological deviation data for a user named ${userName} and provide a non-diagnostic, teen-friendly explanation and general wellness tips.

      **Strict Rules (Non-Negotiable):**
      1.  **NO DIAGNOSIS:** Never use words like "diagnose," "condition," "disease," "illness," "symptom," "disorder," or any medical terminology. Do not mention specific medical conditions (e.g., anxiety, depression, heart problems).
      2.  **FOCUS ON DEVIATION:** Your role is to explain *patterns of deviation* from the user's personal baseline, not to interpret health status.
      3.  **TEEN-FRIENDLY LANGUAGE:** Use simple, encouraging, and relatable language. Avoid clinical or alarming tones. Think of yourself as a friendly wellness coach.
      4.  **GENERAL RECOMMENDATIONS ONLY:** Suggestions must be general wellness habits (e.g., hydration, gentle stretching, mindful breathing, balanced nutrition). Do not suggest specific treatments, supplements, or therapies.
      5.  **DISCLAIMER:** Always include the phrase "this is not medical advice" in the explanation.
      6.  **JSON OUTPUT:** The final output must be a single JSON object inside a \`\`\`json block.

      **INPUT DATA:**
      - Anomaly Score: ${result.score.toFixed(3)}
      - Deviation Level: "${result.level}"
      - Primary Contributors (percentage points): 
        - HRV Drop: ${result.contributors.hrv}%
        - Sleep Deficit: ${result.contributors.sleep}%
        - HR Change: ${result.contributors.hr}%
        - Mood/Stress: ${result.contributors.mood}%

      **TASK:**
      Based on the data, generate a JSON object with two keys: "explanation" and "recommendations".

      -   **explanation:** A short paragraph (2-4 sentences) explaining what the deviation level means in simple terms. Connect it to the top one or two contributors from the data.
      -   **recommendations:** An array of 3 short, actionable, and encouraging wellness tips.

      **EXAMPLE TONE & STRUCTURE:**
      -   For "Mild Deviation" driven by sleep: "Hey ${userName}, it looks like your body's patterns are slightly different from your usual baseline today. The main reason seems to be getting a bit less sleep than you're used to. Remember, this is just about noticing trends, and it's not medical advice."
      -   For "Moderate Pattern" driven by HRV: "Hey ${userName}, your body seems to be under a bit more stress than usual, as shown by a change in your typical heart rate variability. This is a common signal that your system might need more recovery time. This is not medical advice, just an observation of your personal trends."

      **PRODUCE THE JSON OUTPUT NOW:**
    `;
  }

  private getOfflineInterpretation(level: AnomalyScoreResult['level']): { aiExplanation: string, recommendations: string[] } {
    const baseExplanation = "The AI interpretation feature is currently offline. Based on the calculated score, your body's patterns show a";
    const baseRecommendations = [
      "Stay hydrated through the day.",
      "Consider some light stretching or a short walk.",
      "Take a few minutes for deep, mindful breathing."
    ];

    switch (level) {
      case 'Stable':
        return {
          aiExplanation: "The AI interpretation feature is currently offline. Your physiological markers are consistent with your personal baseline. Keep up the great work!",
          recommendations: [
            "Keep up your consistent daily routines.",
            "Continue prioritizing quality sleep.",
            "Take a moment to appreciate your stability!"
          ]
        };
      case 'Mild Deviation':
        return {
          aiExplanation: `${baseExplanation} mild deviation from your personal baseline. This is not medical advice, but a small shift like this is common and often related to daily factors like sleep or stress.`,
          recommendations: baseRecommendations
        };
      case 'Moderate Pattern':
        return {
          aiExplanation: `${baseExplanation} moderate deviation from your baseline, suggesting your body might be working harder to adapt. This is not medical advice, but it's a good time to focus on recovery and wellness habits.`,
          recommendations: baseRecommendations
        };
      case 'Significant Deviation':
        return {
          aiExplanation: `${baseExplanation} significant deviation from your baseline. Your body's systems appear to be under considerable load. This is not medical advice, but prioritizing rest and recovery is highly encouraged.`,
          recommendations: baseRecommendations
        };
    }
  }
}

import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule, ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { HealthMonitoringService, HealthData, BaselineData, AnomalyScoreResult } from './services/health-monitoring.service';

type ViewState = 'INPUT' | 'ANALYZING' | 'RESULT';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule],
  templateUrl: './app.component.html',
})
export class AppComponent {
  private healthService = inject(HealthMonitoringService);
  private fb = inject(FormBuilder);

  viewState = signal<ViewState>('INPUT');
  userName = signal('Alex'); // Default user name

  // Default baseline data for the simulation
  baseline = signal<BaselineData>({
    hr: 62,    // Resting HR
    hrv: 55,   // HRV in ms (rMSSD)
    sleep: 7.5 // Hours
  });

  // User input form
  healthForm = this.fb.group({
    hr: [68, [Validators.required, Validators.min(30), Validators.max(200)]],
    hrv: [41, [Validators.required, Validators.min(10), Validators.max(200)]],
    mood: [5, [Validators.required, Validators.min(1), Validators.max(10)]],
    sleep: [6.0, [Validators.required, Validators.min(0), Validators.max(24)]],
  });

  // Stores the final analysis result
  analysisResult = signal<AnomalyScoreResult | null>(null);

  // Computed properties for the UI
  anomalyScorePercent = computed(() => {
    const score = this.analysisResult()?.score;
    return score ? Math.round(score * 100) : 0;
  });

  gaugeRotation = computed(() => {
    const score = this.analysisResult()?.score ?? 0;
    // Map score (0-1) to rotation (-90deg to 90deg)
    return score * 180 - 90;
  });

  gaugeColorClass = computed(() => {
    const level = this.analysisResult()?.level;
    switch (level) {
      case 'Stable': return 'text-neon-green';
      case 'Mild Deviation': return 'text-yellow-400';
      case 'Moderate Pattern': return 'text-orange-500';
      case 'Significant Deviation': return 'text-red-500';
      default: return 'text-slate-500';
    }
  });

  async runAnalysis() {
    if (this.healthForm.invalid) return;

    this.viewState.set('ANALYZING');
    this.analysisResult.set(null);

    const currentData = this.healthForm.value as HealthData;

    // Simulate a delay for analysis
    await new Promise(resolve => setTimeout(resolve, 1500));

    // 1. Calculate the core score
    const scoreData = this.healthService.calculateAnomalyScore(currentData, this.baseline());

    // 2. Get AI interpretation
    const { aiExplanation, recommendations } = await this.healthService.getAiInterpretation(scoreData, this.userName());

    // 3. Set the final result
    this.analysisResult.set({
      ...scoreData,
      aiExplanation,
      recommendations
    });

    this.viewState.set('RESULT');
  }

  startOver() {
    this.viewState.set('INPUT');
    this.healthForm.patchValue({
        hr: 68,
        hrv: 41,
        mood: 5,
        sleep: 6.0,
    });
    this.analysisResult.set(null);
  }
}

