// --- TYPE DEFINITIONS ---

export interface CellCount {
  [cellType: string]: number; // e.g., { RBC: 4.8, WBC: 7.5, Platelets: 250 }
}

export interface GeneticMarker {
  id: string;
  name: string;
  sequence: string;
  mutationPosition?: number;
}

export interface AnalysisResult {
  summary: string;
  potentialConditions: string[];
  confidence: number;
  cellCounts: CellCount;
  geneticMarkers: GeneticMarker[];
  microscopicDescription: string;
}

export interface DiseaseProfile {
  id: string;
  name: string;
  description: string;
  type: 'Healthy' | 'Anemia' | 'Infection' | 'Leukemia' | 'Genetic';
  template: AnalysisResult;
}

