import { Injectable } from '@angular/core';
import { AnalysisResult } from './analysis.service';

// Because we are loading jsPDF from a script tag, we need to declare it to TypeScript
declare const jsPDF: any;

@Injectable({
  providedIn: 'root'
})
export class PdfService {

  generateReport(result: AnalysisResult, patientName: string, patientAge: number, patientSex: string) {
    const doc = new jsPDF.default();
    const pageWidth = doc.internal.pageSize.getWidth();

    // Header
    doc.setFontSize(22);
    doc.setTextColor(40);
    doc.text('Simulated Blood Analysis Report', pageWidth / 2, 20, { align: 'center' });

    doc.setFontSize(11);
    doc.setTextColor(100);
    doc.text(`Patient Name: ${patientName}`, 14, 35);
    doc.text(`Patient Age: ${patientAge}`, 14, 42);
    doc.text(`Patient Sex: ${patientSex}`, 14, 49);
    doc.text(`Report Date: ${new Date().toLocaleDateString()}`, pageWidth - 14, 35, { align: 'right' });

    // Summary Section
    this.addSectionHeader(doc, 'Analysis Summary', 65);
    doc.setFontSize(11);
    const summaryLines = doc.splitTextToSize(result.summary, pageWidth - 28);
    doc.text(summaryLines, 14, 75);

    // Potential Conditions
    this.addSectionHeader(doc, 'Potential Conditions Noted', 95);
    doc.text(result.potentialConditions.join(', '), 14, 105);
    doc.setFontSize(10);
    doc.setTextColor(150);
    doc.text(`Confidence Score: ${(result.confidence * 100).toFixed(1)}%`, 14, 112);

    // Cell Counts Table
    this.addSectionHeader(doc, 'Simulated Cell Counts', 125);
    const cellData = Object.entries(result.cellCounts).map(([key, value]) => [key, value]);
    doc.autoTable({
        startY: 135,
        head: [['Cell Type', 'Value']],
        body: cellData,
        theme: 'striped',
        headStyles: { fillColor: [22, 160, 133] }
    });

    // Genetic Markers
    const finalY = (doc as any).lastAutoTable.finalY || 150;
    this.addSectionHeader(doc, 'Genetic Markers', finalY + 15);
    const markerData = result.geneticMarkers.map(m => [m.name, m.sequence.substring(0, 20) + '...']);
     doc.autoTable({
        startY: finalY + 25,
        head: [['Marker Name', 'Sequence Snippet']],
        body: markerData,
        theme: 'grid',
        headStyles: { fillColor: [44, 62, 80] }
    });

    // Disclaimer
    const disclaimerY = (doc as any).lastAutoTable.finalY || 240;
    doc.setFontSize(8);
    doc.setTextColor(150);
    const disclaimer = 'This is a simulated, non-diagnostic report for educational purposes only. It is not a substitute for professional medical advice, diagnosis, or treatment.';
    const disclaimerLines = doc.splitTextToSize(disclaimer, pageWidth - 28);
    doc.text(disclaimerLines, 14, disclaimerY + 10);

    // Save the PDF
    doc.save(`Blood_Analysis_Report_${patientName.replace(' ', '_')}.pdf`);
  }

  private addSectionHeader(doc: any, title: string, y: number) {
    doc.setFontSize(16);
    doc.setTextColor(44, 62, 80);
    doc.text(title, 14, y);
    doc.setDrawColor(22, 160, 133);
    doc.line(14, y + 2, doc.internal.pageSize.getWidth() - 14, y + 2);
  }
}

import { Component, input, viewChild, ElementRef, AfterViewInit, OnChanges } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AnalysisResult } from '../services/analysis.service';

@Component({
  selector: 'app-cell-canvas',
  standalone: true,
  imports: [CommonModule],
  template: `<canvas #canvas class="w-full h-full rounded-lg bg-slate-900/50 border border-slate-700"></canvas>`,
})
export class CellCanvasComponent implements AfterViewInit, OnChanges {
  canvasEl = viewChild.required<ElementRef<HTMLCanvasElement>>('canvas');
  analysisResult = input.required<AnalysisResult>();

  private ctx: CanvasRenderingContext2D | null = null;
  private cells: any[] = [];
  private isInitialized = false;

  ngAfterViewInit() {
    const canvas = this.canvasEl().nativeElement;
    this.ctx = canvas.getContext('2d');
    this.resizeCanvas();
    this.generateCells();
    this.animate();
    this.isInitialized = true;
    window.addEventListener('resize', () => this.resizeCanvas());
  }

  ngOnChanges() {
    if (this.isInitialized) {
      this.generateCells();
    }
  }

  private resizeCanvas() {
    const canvas = this.canvasEl().nativeElement;
    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;
    if (this.isInitialized) {
      this.generateCells();
    }
  }

  private generateCells() {
    if (!this.ctx) return;
    this.cells = [];
    const { width, height } = this.ctx.canvas;
    const result = this.analysisResult();
    const totalWBC = result.cellCounts['WBC'] ?? 7;

    // Red Blood Cells
    const rbcCount = 150; 
    for (let i = 0; i < rbcCount; i++) {
      this.cells.push({
        type: 'rbc',
        x: Math.random() * width,
        y: Math.random() * height,
        radius: 6 + Math.random() * 2,
        dx: (Math.random() - 0.5) * 0.2,
        dy: (Math.random() - 0.5) * 0.2,
      });
    }

    // White Blood Cells (fewer, larger)
    const wbcCount = Math.min(Math.round(totalWBC / 2), 15);
    for (let i = 0; i < wbcCount; i++) {
       this.cells.push({
        type: 'wbc',
        x: Math.random() * width,
        y: Math.random() * height,
        radius: 12 + Math.random() * 3,
        dx: (Math.random() - 0.5) * 0.1,
        dy: (Math.random() - 0.5) * 0.1,
      });
    }

    // Platelets (many, tiny)
    const plateletCount = 100;
     for (let i = 0; i < plateletCount; i++) {
       this.cells.push({
        type: 'platelet',
        x: Math.random() * width,
        y: Math.random() * height,
        radius: 2 + Math.random(),
        dx: (Math.random() - 0.5) * 0.4,
        dy: (Math.random() - 0.5) * 0.4,
      });
    }
  }

  private animate() {
    if (!this.ctx) return;
    const { width, height } = this.ctx.canvas;
    this.ctx.clearRect(0, 0, width, height);

    for (const cell of this.cells) {
      cell.x += cell.dx;
      cell.y += cell.dy;

      // Wall collision
      if (cell.x - cell.radius < 0 || cell.x + cell.radius > width) cell.dx *= -1;
      if (cell.y - cell.radius < 0 || cell.y + cell.radius > height) cell.dy *= -1;

      this.drawCell(cell);
    }
    requestAnimationFrame(() => this.animate());
  }

  private drawCell(cell: any) {
    if (!this.ctx) return;
    this.ctx.beginPath();
    this.ctx.arc(cell.x, cell.y, cell.radius, 0, Math.PI * 2);

    if (cell.type === 'rbc') {
      this.ctx.fillStyle = 'rgba(239, 68, 68, 0.6)';
      this.ctx.strokeStyle = 'rgba(220, 38, 38, 0.8)';
    } else if (cell.type === 'wbc') {
      this.ctx.fillStyle = 'rgba(168, 85, 247, 0.6)';
      this.ctx.strokeStyle = 'rgba(147, 51, 234, 0.8)';
    } else { // platelet
      this.ctx.fillStyle = 'rgba(236, 236, 236, 0.7)';
      this.ctx.strokeStyle = 'rgba(200, 200, 200, 0.9)';
    }

    this.ctx.fill();
    this.ctx.stroke();
    this.ctx.closePath();
  }
}

