        model: 'gemini-2.5-flash',
        config: {
          systemInstruction: "You are a helpful assistant for a simulated blood analysis app. Explain concepts in simple terms. You must strictly refuse to give any medical advice, diagnosis, or treatment suggestions. Your role is purely educational and for a simulation.",
        }
    });
  }

  async sendMessage() {
    if (!this.newMessage.trim() || this.isLoading) return;

    const userMessage: Message = { sender: 'user', text: this.newMessage };
    this.messages.push(userMessage);
    this.isLoading = true;
    const tempMessage = this.newMessage;
    this.newMessage = '';

    try {
        const response = await this.chat.sendMessage({ message: tempMessage });
        const aiMessage: Message = { sender: 'ai', text: response.text };
        this.messages.push(aiMessage);
    } catch (e) {
        this.messages.push({ sender: 'ai', text: 'Sorry, I encountered an error. Please try again.' });
        console.error(e);
    } finally {
        this.isLoading = false;
    }
  }
}

