import { FormsModule, ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { LogoGalleryComponent } from './components/logo-gallery.component';

type ViewState = 'LOGIN' | 'DASHBOARD' | 'MANUAL_ENTRY' | 'LOADING';
type UserType = 'PATIENT' | 'DOCTOR';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, CellCanvasComponent, ChatAssistantComponent, FormsModule, ReactiveFormsModule, LogoGalleryComponent],
  templateUrl: './app.component.html'
})
export class AppComponent implements OnInit {
  private analysisService = inject(AnalysisService);
  private pdfService = inject(PdfService);
  private fb: FormBuilder = inject(FormBuilder);

  viewState = signal<ViewState>('LOGIN');

  // Login Mode Toggle
  loginTab = signal<UserType>('DOCTOR');

  currentProfile = signal<DiseaseProfile | null>(null);
  currentResult = signal<AnalysisResult | null>(null);
  uploadedImage = signal<string | null>(null);

  // Track current user state
  currentUserType = signal<UserType>('DOCTOR');
  currentUserName = signal<string>('');

  // PWA Install State
  installPromptEvent = signal<any>(null);
  showInstallHelp = signal(false);

  patientInfo = { name: '', id: '', age: 0, sex: 'Unknown' };

  // Staff Login Form
  staffForm = this.fb.group({
    username: ['', Validators.required],
    password: ['', Validators.required]
  });

  // Patient Login Form
  patientForm = this.fb.group({
    fullName: ['', Validators.required],
    patientId: ['', [Validators.required, Validators.minLength(4)]] // UID
  });

  // Manual Analysis Form
  manualForm = this.fb.group({
    description: [''],
    image: [null],
    age: [35, [Validators.required, Validators.min(0)]],
    sex: ['Female', Validators.required],
    // Biometrics (Optional)
    hemoglobin: [null as number | null],
    wbc: [null as number | null],
    platelets: [null as number | null],
    mcv: [null as number | null],
  });

  availableDiseases = this.analysisService.getLibrary();

  ngOnInit() {
    this.currentProfile.set(this.availableDiseases[0]); 
    this.currentResult.set(this.availableDiseases[0].template);

    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      this.installPromptEvent.set(e);
    });
  }

  // --- Auth Methods ---

  handlePatientLogin() {
    if (this.patientForm.valid) {
      const { fullName, patientId } = this.patientForm.value;

      this.currentUserType.set('PATIENT');
      this.currentUserName.set(fullName || 'Patient');

      this.patientInfo = {
        name: fullName || 'Patient',
        id: patientId || '0000',
        age: 0,
        sex: 'Unknown'
      };

      this.enterManualMode();
    }
  }

  continueAsGuest() {
    let guestName = this.patientForm.value.fullName?.trim();

    if (!guestName) {
        const input = prompt("Please enter a Patient Name for the session report (Optional):");
        guestName = input ? input.trim() : null;
    }

    const finalName = guestName || 'Guest User';

    this.currentUserType.set('PATIENT');
    this.currentUserName.set(finalName);

    this.patientInfo = {
      name: finalName,
      id: 'GUEST-ACCESS',
      age: 30, 
      sex: 'Unknown'
    };

    this.enterManualMode();
  }

  handleStaffLogin() {
    if (this.staffForm.valid) {
      const { username, password } = this.staffForm.value;

      if (password === 'Shiv@.pm2010') {
        this.currentUserType.set('DOCTOR');
        this.currentUserName.set(`Dr. ${username || 'User'}`);
        this.viewState.set('DASHBOARD');
      } else {
        alert('Access Denied: Incorrect Access Key.');
        this.staffForm.get('password')?.reset();
      }
    }
  }

  signOut() {
    this.viewState.set('LOGIN');
    this.currentUserType.set('DOCTOR');
    this.currentUserName.set('');
    this.staffForm.reset();
    this.patientForm.reset();
  }

  installApp() {
    const prompt = this.installPromptEvent();
    if (prompt) {
      prompt.prompt();
      prompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          this.installPromptEvent.set(null);
        }
      });
    } else {
      this.showInstallHelp.set(true);
    }
  }

  closeInstallHelp() {
    this.showInstallHelp.set(false);
  }

  // --- App Logic ---

  enterManualMode() {
    this.viewState.set('MANUAL_ENTRY');
    this.uploadedImage.set(null);
    this.manualForm.patchValue({
        description: '',
        age: 35,
        sex: 'Female',
        hemoglobin: null,
        wbc: null,
        platelets: null,
        mcv: null
    });
    this.currentProfile.set(null);
  }

  goBack() {
    if (this.currentResult()) {
        this.viewState.set('DASHBOARD');
    } else {
        if (this.currentUserType() === 'DOCTOR') {
            this.viewState.set('DASHBOARD');
        } else {
            this.signOut();
        }
    }
  }

  loadSample(profile: DiseaseProfile) {
    this.currentProfile.set(profile);
    this.currentResult.set(profile.template);
  }

  onProfileChange(event: Event) {
    const select = event.target as HTMLSelectElement;
    const profileId = select.value;
    if (profileId === 'CUSTOM') {
        this.enterManualMode();
    } else {
        const profile = this.availableDiseases.find(p => p.id === profileId);
        if (profile) {
            this.loadSample(profile);
            this.viewState.set('DASHBOARD');
        }
    }
  }

  onFileSelected(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => this.uploadedImage.set(reader.result as string);
      reader.readAsDataURL(file);
    }
  }

  async runManualAnalysis() {
    this.viewState.set('LOADING');
    try {
        const formVal = this.manualForm.value;
        const desc = formVal.description || '';
        const image = this.uploadedImage();

        const biometrics = {
          hemoglobin: formVal.hemoglobin ?? undefined,
          wbc: formVal.wbc ?? undefined,
          platelets: formVal.platelets ?? undefined,
          mcv: formVal.mcv ?? undefined
        };

        this.patientInfo = {
            ...this.patientInfo,
            age: formVal.age || 0,
            sex: formVal.sex || 'Unknown'
        };

        let result: AnalysisResult;

        if (image) {
            const base64 = image.split(',')[1];
            result = await this.analysisService.analyzeImage(base64);
        } else {
            result = await this.analysisService.analyzeCustomSample(desc || 'Standard blood sample', biometrics);
        }

        this.currentResult.set(result);
        this.currentProfile.set({
          id: 'custom',
          name: image ? 'Image Scan Analysis' : 'Custom Description',
          description: image ? 'Analysis generated from uploaded microscopic image.' : desc,
          type: 'Healthy', 
          template: result
        });
        this.viewState.set('DASHBOARD');
    } catch (e) {
        console.error(e);
        this.viewState.set('MANUAL_ENTRY');
        alert("Analysis failed. Please try again.");
    }
  }

  downloadReport() {
    const result = this.currentResult();
    if (result) {
      this.pdfService.generateReport(result, this.patientInfo.name, this.patientInfo.age, this.patientInfo.sex);
    }
  }

  getDnaSegments(sequence: string, mutationPos?: number) {
    return sequence.split('').map((char, index) => {
      const isMutated = mutationPos && Math.abs(index - mutationPos) <= 0; 

      let colorClass = 'text-slate-400';
      if (char === 'A') colorClass = 'text-green-400';
      if (char === 'T') colorClass = 'text-blue-400';
      if (char === 'C') colorClass = 'text-red-400';
      if (char === 'G') colorClass = 'text-yellow-400';

      if (isMutated) {
          colorClass = 'text-white bg-yellow-600 px-0.5 rounded font-bold animate-pulse';
      }

      return { char, colorClass };
    });
  }
}

