import { Injectable } from '@angular/core';
import { GoogleGenAI } from '@google/genai';

export interface HealthData {
  hr: number;       // Heart Rate (beats per minute)
  hrv: number;      // Heart Rate Variability (ms)
  mood: number;     // Self-reported mood (1-10)
  sleep: number;    // Sleep duration (hours)
}

export interface BaselineData {
  hr: number;
  hrv: number;
  sleep: number;
}

export interface AnomalyScoreResult {
  score: number; // 0 to 1
  level: 'Stable' | 'Mild Deviation' | 'Moderate Pattern' | 'Significant Deviation';
  contributors: {
    hr: number;
    hrv: number;
    mood: number;
    sleep: number;
  };
  aiExplanation: string;
  recommendations: string[];
}

@Injectable({
  providedIn: 'root'
})
export class HealthMonitoringService {
  private ai: GoogleGenAI;
  private weights = {
    hr: 0.20,
    hrv: 0.40,
    mood: 0.15,
    sleep: 0.25,
  };

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  calculateAnomalyScore(current: HealthData, baseline: BaselineData): Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'> {
    // 1. Calculate individual deviation scores (D_x)
    const d_hr = Math.min(1, Math.abs(current.hr - baseline.hr) / (baseline.hr * 0.5));
    const d_hrv = Math.min(1, Math.max(0, (baseline.hrv - current.hrv) / baseline.hrv));
    const d_mood = (10 - current.mood) / 9;
    const d_sleep = Math.min(1, Math.max(0, (baseline.sleep - current.sleep) / baseline.sleep));

    // 2. Calculate weighted contributions
    const contrib_hr = this.weights.hr * d_hr;
    const contrib_hrv = this.weights.hrv * d_hrv;
    const contrib_mood = this.weights.mood * d_mood;
    const contrib_sleep = this.weights.sleep * d_sleep;

    // 3. Calculate final Anomaly Score (AS)
    const score = contrib_hr + contrib_hrv + contrib_mood + contrib_sleep;

    // 4. Classify anomaly level
    let level: AnomalyScoreResult['level'];
    if (score < 0.20) level = 'Stable';
    else if (score < 0.40) level = 'Mild Deviation';
    else if (score < 0.60) level = 'Moderate Pattern';
    else level = 'Significant Deviation';

    return {
      score: Math.round(score * 1000) / 1000, // Round to 3 decimal places
      level,
      contributors: {
        hr: Math.round(contrib_hr * 100),
        hrv: Math.round(contrib_hrv * 100),
        mood: Math.round(contrib_mood * 100),
        sleep: Math.round(contrib_sleep * 100),
      }
    };
  }

  async getAiInterpretation(result: Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'>, userName: string): Promise<{aiExplanation: string, recommendations: string[]}> {
    const apiKey = process.env['API_KEY'];
    if (!apiKey || apiKey.length < 10) {
      return this.getOfflineInterpretation(result.level);
    }

    const prompt = this.constructGeminiPrompt(result, userName);

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      const text = response.text;

      // Extract JSON from the response
      const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/);
      if (jsonMatch && jsonMatch[1]) {
        const parsed = JSON.parse(jsonMatch[1]);
        return {
           aiExplanation: parsed.explanation,
           recommendations: parsed.recommendations
        };
      } else {
        return this.getOfflineInterpretation(result.level);
      }
    } catch (error) {
      console.error("Gemini API error:", error);
      return this.getOfflineInterpretation(result.level);
    }
  }

  private constructGeminiPrompt(result: Omit<AnomalyScoreResult, 'aiExplanation' | 'recommendations'>, userName: string): string {
    return `
      **SYSTEM PROMPT: ACT AS A PREVENTATIVE WELLNESS AI FOR A TEENAGER**

      **Objective:** Analyze physiological deviation data for a user named ${userName} and provide a non-diagnostic, teen-friendly explanation and general wellness tips.

      **Strict Rules (Non-Negotiable):**
      1.  **NO DIAGNOSIS:** Never use words like "diagnose," "condition," "disease," "illness," "symptom," "disorder," or any medical terminology. Do not mention specific medical conditions (e.g., anxiety, depression, heart problems).
      2.  **FOCUS ON DEVIATION:** Your role is to explain *patterns of deviation* from the user's personal baseline, not to interpret health status.
      3.  **TEEN-FRIENDLY LANGUAGE:** Use simple, encouraging, and relatable language. Avoid clinical or alarming tones. Think of yourself as a friendly wellness coach.
      4.  **GENERAL RECOMMENDATIONS ONLY:** Suggestions must be general wellness habits (e.g., hydration, gentle stretching, mindful breathing, balanced nutrition). Do not suggest specific treatments, supplements, or therapies.
      5.  **DISCLAIMER:** Always include the phrase "this is not medical advice" in the explanation.
      6.  **JSON OUTPUT:** The final output must be a single JSON object inside a \`\`\`json block.

      **INPUT DATA:**
      - Anomaly Score: ${result.score.toFixed(3)}
      - Deviation Level: "${result.level}"
      - Primary Contributors (percentage points): 
        - HRV Drop: ${result.contributors.hrv}%
        - Sleep Deficit: ${result.contributors.sleep}%
        - HR Change: ${result.contributors.hr}%
        - Mood/Stress: ${result.contributors.mood}%

      **TASK:**
      Based on the data, generate a JSON object with two keys: "explanation" and "recommendations".

      -   **explanation:** A short paragraph (2-4 sentences) explaining what the deviation level means in simple terms. Connect it to the top one or two contributors from the data.
      -   **recommendations:** An array of 3 short, actionable, and encouraging wellness tips.

      **EXAMPLE TONE & STRUCTURE:**
      -   For "Mild Deviation" driven by sleep: "Hey ${userName}, it looks like your body's patterns are slightly different from your usual baseline today. The main reason seems to be getting a bit less sleep than you're used to. Remember, this is just about noticing trends, and it's not medical advice."
      -   For "Moderate Pattern" driven by HRV: "Hey ${userName}, your body seems to be under a bit more stress than usual, as shown by a change in your typical heart rate variability. This is a common signal that your system might need more recovery time. This is not medical advice, just an observation of your personal trends."

      **PRODUCE THE JSON OUTPUT NOW:**
    `;
  }

  private getOfflineInterpretation(level: AnomalyScoreResult['level']): { aiExplanation: string, recommendations: string[] } {
    const baseExplanation = "The AI interpretation feature is currently offline. Based on the calculated score, your body's patterns show a";
    const baseRecommendations = [
      "Stay hydrated through the day.",
      "Consider some light stretching or a short walk.",
      "Take a few minutes for deep, mindful breathing."
    ];

    switch (level) {
      case 'Stable':
        return {
          aiExplanation: "The AI interpretation feature is currently offline. Your physiological markers are consistent with your personal baseline. Keep up the great work!",
          recommendations: [
            "Keep up your consistent daily routines.",
            "Continue prioritizing quality sleep.",
            "Take a moment to appreciate your stability!"
          ]
        };
      case 'Mild Deviation':
        return {
          aiExplanation: `${baseExplanation} mild deviation from your personal baseline. This is not medical advice, but a small shift like this is common and often related to daily factors like sleep or stress.`,
          recommendations: baseRecommendations
        };
      case 'Moderate Pattern':
        return {
          aiExplanation: `${baseExplanation} moderate deviation from your baseline, suggesting your body might be working harder to adapt. This is not medical advice, but it's a good time to focus on recovery and wellness habits.`,
          recommendations: baseRecommendations
        };
      case 'Significant Deviation':
        return {
          aiExplanation: `${baseExplanation} significant deviation from your baseline. Your body's systems appear to be under considerable load. This is not medical advice, but prioritizing rest and recovery is highly encouraged.`,
          recommendations: baseRecommendations
        };
    }
  }
}

import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule, ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { HealthMonitoringService, HealthData, BaselineData, AnomalyScoreResult } from './services/health-monitoring.service';

type ViewState = 'INPUT' | 'ANALYZING' | 'RESULT';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule],
  templateUrl: './app.component.html',
})
export class AppComponent {
  private healthService = inject(HealthMonitoringService);
  private fb = inject(FormBuilder);

  viewState = signal<ViewState>('INPUT');
  userName = signal('Alex'); // Default user name

  // Default baseline data for the simulation
  baseline = signal<BaselineData>({
    hr: 62,    // Resting HR
    hrv: 55,   // HRV in ms (rMSSD)
    sleep: 7.5 // Hours
  });

  // User input form
  healthForm = this.fb.group({
    hr: [68, [Validators.required, Validators.min(30), Validators.max(200)]],
    hrv: [41, [Validators.required, Validators.min(10), Validators.max(200)]],
    mood: [5, [Validators.required, Validators.min(1), Validators.max(10)]],
    sleep: [6.0, [Validators.required, Validators.min(0), Validators.max(24)]],
  });

  // Stores the final analysis result
  analysisResult = signal<AnomalyScoreResult | null>(null);

  // Computed properties for the UI
  anomalyScorePercent = computed(() => {
    const score = this.analysisResult()?.score;
    return score ? Math.round(score * 100) : 0;
  });

  gaugeRotation = computed(() => {
    const score = this.analysisResult()?.score ?? 0;
    // Map score (0-1) to rotation (-90deg to 90deg)
    return score * 180 - 90;
  });

  gaugeColorClass = computed(() => {
    const level = this.analysisResult()?.level;
    switch (level) {
      case 'Stable': return 'text-neon-green';
      case 'Mild Deviation': return 'text-yellow-400';
      case 'Moderate Pattern': return 'text-orange-500';
      case 'Significant Deviation': return 'text-red-500';
      default: return 'text-slate-500';
    }
  });

  async runAnalysis() {
    if (this.healthForm.invalid) return;

    this.viewState.set('ANALYZING');
    this.analysisResult.set(null);

    const currentData = this.healthForm.value as HealthData;

    // Simulate a delay for analysis
    await new Promise(resolve => setTimeout(resolve, 1500));

    // 1. Calculate the core score
    const scoreData = this.healthService.calculateAnomalyScore(currentData, this.baseline());

    // 2. Get AI interpretation
    const { aiExplanation, recommendations } = await this.healthService.getAiInterpretation(scoreData, this.userName());

    // 3. Set the final result
    this.analysisResult.set({
      ...scoreData,
      aiExplanation,
      recommendations
    });

    this.viewState.set('RESULT');
  }

  startOver() {
    this.viewState.set('INPUT');
    this.healthForm.patchValue({
        hr: 68,
        hrv: 41,
        mood: 5,
        sleep: 6.0,
    });
    this.analysisResult.set(null);
  }
}

